import java.util.*;
public class DequeDemo {
    public static void main(String[] a){
        Deque<Integer> dq=new ArrayDeque<>();
        dq.offerFirst(2);dq.offerFirst(1); // front: [1,2]
        dq.offerLast(3);dq.offerLast(4);   // back: [1,2,3,4]
        System.out.println("front: "+dq.peekFirst()); // 1
        System.out.println("back: "+dq.peekLast());   // 4
        dq.pollFirst(); dq.pollLast();
        System.out.println("after poll both: "+dq); // [2,3]
        System.out.println("Deque: O(1) at BOTH ends — stack+queue combined");
    }
}

import java.util.*;
public class SWMax {
    public static int[] maxSlidingWindow(int[] nums, int k) {
        int n=nums.length; int[] res=new int[n-k+1]; Deque<Integer> dq=new ArrayDeque<>();
        for(int i=0;i<n;i++){
            if(!dq.isEmpty()&&dq.peekFirst()<=i-k) dq.pollFirst();
            while(!dq.isEmpty()&&nums[dq.peekLast()]<=nums[i]) dq.pollLast();
            dq.offerLast(i);
            if(i>=k-1) res[i-k+1]=nums[dq.peekFirst()];
        }
        return res;
    }
    public static void main(String[] a){
        System.out.println(Arrays.toString(maxSlidingWindow(new int[]{1,3,-1,-3,5,3,6,7},3)));
        System.out.println(Arrays.toString(maxSlidingWindow(new int[]{1},1)));
        System.out.println("O(n) monotonic decreasing deque of indices");
    }
}

