import java.util.*;
public class JumpI {
    public static boolean canJump(int[] nums) {
        int maxReach=0;
        for(int i=0;i<nums.length;i++){
            if(i>maxReach) return false;
            maxReach=Math.max(maxReach,i+nums[i]);
        }
        return true;
    }
    public static void main(String[] a){
        System.out.println(canJump(new int[]{2,3,1,1,4})); // true
        System.out.println(canJump(new int[]{3,2,1,0,4})); // false
        System.out.println("O(n) greedy — track max reachable index");
    }
}

import java.util.*;
public class JumpII {
    public static int jump(int[] nums) {
        int jumps=0,currEnd=0,farthest=0;
        for(int i=0;i<nums.length-1;i++){
            farthest=Math.max(farthest,i+nums[i]);
            if(i==currEnd){jumps++;currEnd=farthest;}
        }
        return jumps;
    }
    public static void main(String[] a){
        System.out.println(jump(new int[]{2,3,1,1,4})); // 2
        System.out.println(jump(new int[]{2,3,0,1,4})); // 2
        System.out.println("O(n) greedy BFS-like — currEnd is current jump range boundary");
    }
}

