import java.util.*;
public class AbsDiffWindow {
    public static int longestSubarray(int[] nums, int limit) {
        Deque<Integer> maxDq=new ArrayDeque<>(),minDq=new ArrayDeque<>();
        int lo=0,res=0;
        for(int hi=0;hi<nums.length;hi++){
            while(!maxDq.isEmpty()&&nums[maxDq.peekLast()]<=nums[hi])maxDq.pollLast();maxDq.offerLast(hi);
            while(!minDq.isEmpty()&&nums[minDq.peekLast()]>=nums[hi])minDq.pollLast();minDq.offerLast(hi);
            while(nums[maxDq.peekFirst()]-nums[minDq.peekFirst()]>limit){lo++;if(maxDq.peekFirst()<lo)maxDq.pollFirst();if(minDq.peekFirst()<lo)minDq.pollFirst();}
            res=Math.max(res,hi-lo+1);
        }
        return res;
    }
    public static void main(String[] a){
        System.out.println(longestSubarray(new int[]{8,2,4,7},4)); // 2
        System.out.println(longestSubarray(new int[]{10,1,2,4,7,2},5)); // 4
        System.out.println("O(n) — two monotonic deques (max and min simultaneously)");
    }
}

import java.util.*;
public class ShortestSubK {
    public static int shortestSubarray(int[] nums, int k) {
        int n=nums.length; long[] prefix=new long[n+1]; for(int i=0;i<n;i++) prefix[i+1]=prefix[i]+nums[i];
        Deque<Integer> dq=new ArrayDeque<>(); int res=Integer.MAX_VALUE;
        for(int i=0;i<=n;i++){
            while(!dq.isEmpty()&&prefix[i]-prefix[dq.peekFirst()]>=k) res=Math.min(res,i-dq.pollFirst());
            while(!dq.isEmpty()&&prefix[dq.peekLast()]>=prefix[i]) dq.pollLast();
            dq.offerLast(i);
        }
        return res==Integer.MAX_VALUE?-1:res;
    }
    public static void main(String[] a){
        System.out.println(shortestSubarray(new int[]{1},1)); // 1
        System.out.println(shortestSubarray(new int[]{1,2},4)); // -1
        System.out.println(shortestSubarray(new int[]{2,-1,2},3)); // 3
        System.out.println("O(n) — prefix sums + monotonic deque (handles negatives!)");
    }
}

import java.util.*;
public class DequeMultiMode {
    public static void main(String[] a){
        // Mode 1: Stack (LIFO) — use Front
        Deque<Integer> stack=new ArrayDeque<>();
        stack.push(1);stack.push(2);stack.push(3); // addFirst
        System.out.println("Stack (LIFO): "+stack.pop()+","+stack.pop()); // 3,2
        // Mode 2: Queue (FIFO) — offer=addLast, poll=removeFirst
        Deque<Integer> queue=new ArrayDeque<>();
        queue.offer(1);queue.offer(2);queue.offer(3); // addLast
        System.out.println("Queue (FIFO): "+queue.poll()+","+queue.poll()); // 1,2
        // Mode 3: Sliding window — use BOTH ends
        System.out.println("Deque = stack + queue + sliding window support");
    }
}

import java.util.*;
public class CircularDeque {
    // Design circular deque with fixed capacity k
    static class MyCircularDeque {
        Deque<Integer> dq=new ArrayDeque<>(); int cap;
        MyCircularDeque(int k){cap=k;}
        boolean insertFront(int v){if(isFull())return false;dq.offerFirst(v);return true;}
        boolean insertLast(int v){if(isFull())return false;dq.offerLast(v);return true;}
        boolean deleteFront(){if(isEmpty())return false;dq.pollFirst();return true;}
        boolean deleteLast(){if(isEmpty())return false;dq.pollLast();return true;}
        int getFront(){return isEmpty()?-1:dq.peekFirst();}
        int getRear(){return isEmpty()?-1:dq.peekLast();}
        boolean isEmpty(){return dq.isEmpty();}
        boolean isFull(){return dq.size()==cap;}
    }
    public static void main(String[] a){
        MyCircularDeque cd=new MyCircularDeque(3);
        System.out.println(cd.insertLast(1));  // true
        System.out.println(cd.insertLast(2));  // true
        System.out.println(cd.insertFront(3)); // true
        System.out.println(cd.insertFront(4)); // false (full)
        System.out.println(cd.getRear());      // 2
        System.out.println(cd.isFull());       // true
    }
}

import java.util.*;
public class DequeSynth {
    static int[] swMax(int[] nums,int k){int n=nums.length;int[] r=new int[n-k+1];Deque<Integer> dq=new ArrayDeque<>();for(int i=0;i<n;i++){if(!dq.isEmpty()&&dq.peekFirst()<=i-k)dq.pollFirst();while(!dq.isEmpty()&&nums[dq.peekLast()]<=nums[i])dq.pollLast();dq.offerLast(i);if(i>=k-1)r[i-k+1]=nums[dq.peekFirst()];}return r;}
    static int minJumps(int[] nums){int j=0,end=0,far=0;for(int i=0;i<nums.length-1;i++){far=Math.max(far,i+nums[i]);if(i==end){j++;end=far;}}return j;}
    public static void main(String[] a){
        System.out.println(Arrays.toString(swMax(new int[]{1,3,-1,-3,5,3,6,7},3)));
        System.out.println(minJumps(new int[]{2,3,1,1,4}));
        boolean ok=Arrays.toString(swMax(new int[]{1,3,-1,-3,5,3,6,7},3)).equals("[3, 3, 5, 5, 6, 7]")&&minJumps(new int[]{2,3,1,1,4})==2;
        System.out.println("All pass: "+ok);
    }
}

